insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 0, 'question', 'Are you running from something you should face?', NULL, 'shadow', 3, '"Running" means avoiding, distracting yourself, or postponing — not necessarily fleeing outright.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 1, 'quote', 'One does not become enlightened by imagining figures of light, but by making the darkness conscious.', 'Carl Jung', 'shadow', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 2, 'question', 'Do you judge others for traits you see in yourself?', NULL, 'honesty', 3, 'This includes traits you''re only dimly aware of in yourself, not just ones you''d openly admit to.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 3, 'question', 'Have you been lying to yourself about something important?', NULL, 'truth', 3, 'This means avoiding a truth you already sense on some level, not simply being unsure.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 4, 'vibe', 'Sit with the version of yourself you don''t show anyone.', NULL, 'shadow', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 5, 'question', 'Are you the villain in someone else''s story?', NULL, 'honesty', 3, 'This asks how someone else might cast you in their account, not whether you meant harm.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 6, 'question', 'Do you self-sabotage when things are going well?', NULL, 'shadow', 3, 'Self-sabotage means undermining your own progress, even unconsciously — not just an occasional slip.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 7, 'quote', 'The wound is the place where the light enters you.', 'Rumi', 'wounds', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 8, 'question', 'Do you secretly enjoy other people''s failures?', NULL, 'honesty', 3, '"Secretly" means a private flicker of satisfaction, even one you''d never admit out loud.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('shadows', 9, 'question', 'Are you pretending to be someone you''re not?', NULL, 'identity', 3, 'This can apply to one relationship or context, not necessarily your whole life.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 0, 'question', 'Would you want to be friends with yourself?', NULL, 'reflection', 2, 'Judge this by who you are right now, not who you''re trying to become.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 1, 'question', 'Do people know the real you?', NULL, 'identity', 2, 'This is about the people closest to you, not casual acquaintances or strangers.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 2, 'vibe', 'Look at yourself without any labels. Just you.', NULL, 'reflection', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 3, 'question', 'If you met yourself, would you trust you?', NULL, 'trust', 2, 'Trust here means keeping your word and having your own back, not liking everything about yourself.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 4, 'question', 'Are your values actually reflected in your actions?', NULL, 'honesty', 3, 'Think about your actions over recent months, not a single lapse.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 5, 'quote', 'We don''t see things as they are, we see them as we are.', 'Anais Nin', 'reflection', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 6, 'question', 'Are you the same person in private as in public?', NULL, 'honesty', 2, 'Small social adjustments don''t count — this is about your core character and honesty.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 7, 'question', 'Would your younger self be disappointed in you?', NULL, 'reflection', 3, 'Picture your younger self judging your character and choices, not your job title or income.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 8, 'question', 'Are you kind when no one is watching?', NULL, 'kindness', 2, 'Think of moments with no audience and nothing to gain, not just public politeness.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('mirrors', 9, 'question', 'Do you take more than you give?', NULL, 'honesty', 2, 'Weigh this across your relationships overall, not any single one.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 0, 'question', 'Is there a decision you''ve been avoiding?', NULL, 'decision', 2, '"Avoiding" means you know it needs deciding but keep delaying it, not that you haven''t thought about it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 1, 'question', 'Are you staying somewhere out of fear, not love?', NULL, 'fear', 3, '"Somewhere" can mean a relationship, job, city, or any situation you haven''t left.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 2, 'quote', 'In any moment of decision, the best thing you can do is the right thing. The worst thing you can do is nothing.', 'Theodore Roosevelt', 'decision', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 3, 'question', 'Are you in the right career for your soul?', NULL, 'purpose', 3, '"For your soul" means it feels meaningful to you, not necessarily prestigious or lucrative.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 4, 'vibe', 'Imagine standing at a fork in the road. One path is familiar. One is not.', NULL, 'crossroads', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 5, 'question', 'Are you choosing comfort over growth?', NULL, 'growth', 2, 'Think of a specific choice you''re facing now, not your general life philosophy.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 6, 'question', 'Would you make the same choices if you could start over?', NULL, 'reflection', 3, 'Judge with the knowledge you have now, not by blaming your past self for not knowing it then.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 7, 'question', 'Are you waiting for permission to live your life?', NULL, 'permission', 2, '"Permission" means external approval — from a person, institution, or timeline — not your own readiness.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 8, 'question', 'Is fear making your decisions for you?', NULL, 'fear', 2, 'This is about fear overriding what you actually want, not reasonable caution.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('crossroads', 9, 'quote', 'The only way to make sense out of change is to plunge into it, move with it, and join the dance.', 'Alan Watts', 'acceptance', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 0, 'question', 'Have you forgiven your parents for their mistakes?', NULL, 'forgiveness', 3, 'Forgiving means releasing the resentment — it doesn''t require excusing what happened or reconciling.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 1, 'question', 'Are you repeating patterns from your childhood?', NULL, 'roots', 3, 'This includes patterns you repeat unconsciously, not just ones you''ve deliberately chosen.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 2, 'vibe', 'Think of the place that first felt like home.', NULL, 'belonging', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 3, 'question', 'Are there family wounds you haven''t healed?', NULL, 'wounds', 3, '"Family" here includes any relative, not just parents or siblings.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 4, 'quote', 'The apple doesn''t fall far from the tree, but it can roll.', NULL, 'roots', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 5, 'question', 'Have you become what your family expected?', NULL, 'identity', 2, 'This includes expectations they voiced directly or ones you absorbed without them saying so.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 6, 'question', 'Is there a conversation with family you need to have?', NULL, 'courage', 2, '"Need" means it feels overdue to you, not that anyone is demanding it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 7, 'question', 'Do you know where you come from?', NULL, 'belonging', 1, 'This can mean your family history, heritage, or the place that shaped you — however you read it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 8, 'question', 'Are you running toward something or away from your past?', NULL, 'roots', 3, 'Either direction counts as "running" here — this isn''t about which one is healthier.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('roots', 9, 'question', 'Have you made peace with your upbringing?', NULL, 'acceptance', 3, 'Peace here means you can think about it without it derailing you, not that it never stings.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 0, 'question', 'Are you afraid of dying?', NULL, 'mortality', 3, 'This is about the fact of dying itself, not fear of pain or how it might happen.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 1, 'question', 'Do you know what you''re living for?', NULL, 'purpose', 3, 'This doesn''t require one grand purpose — a person, value, or daily reason can count.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 2, 'quote', 'The meaning of life is to find your gift. The purpose of life is to give it away.', 'Pablo Picasso', 'purpose', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 3, 'question', 'Have you accepted that you won''t live forever?', NULL, 'mortality', 3, '"Accepted" means the thought no longer feels unbearable, not that you never think about it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 4, 'vibe', 'Close your eyes. Imagine looking at Earth from space. You are here.', NULL, 'wonder', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 5, 'question', 'Do you believe you matter in the grand scheme?', NULL, 'identity', 3, '"Matter" can mean cosmic significance or impact on the people and world around you — however you read it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 6, 'question', 'Have you found something worth suffering for?', NULL, 'purpose', 3, '"Suffering" here means real sacrifice or hardship, not everyday inconvenience.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 7, 'question', 'Are you running out of time for what matters most?', NULL, 'mortality', 3, 'This is about how it feels to you right now, not an actuarial calculation.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 8, 'quote', 'We are not human beings having a spiritual experience. We are spiritual beings having a human experience.', 'Pierre Teilhard de Chardin', 'wonder', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('depths', 9, 'question', 'Have you truly lived, or just existed?', NULL, 'purpose', 3, 'Judge this by your own sense of aliveness and engagement, not by outward achievements.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 0, 'question', 'Are you in love right now?', NULL, 'love', 2, 'This means present tense — feelings you''re experiencing now, not memories of past love.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 1, 'question', 'Have you lost someone you still think about?', NULL, 'love', 3, '"Lost" can mean death, breakup, or falling out of touch — any way they''re no longer in your life.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 2, 'vibe', 'Remember the last time someone made your chest feel warm.', NULL, 'love', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 3, 'question', 'Are you afraid of being truly known by someone?', NULL, 'vulnerability', 3, '"Truly known" means someone seeing your flaws and inner world, not just your public self.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 4, 'quote', 'We accept the love we think we deserve.', 'Stephen Chbosky', 'love', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 5, 'question', 'Do you express love the way your people need it?', NULL, 'empathy', 3, '"Need" means how they actually receive love best, which may differ from how you naturally express it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 6, 'question', 'Are you holding onto a love that''s already gone?', NULL, 'letting_go', 3, '"Gone" can mean a relationship that ended, or one that quietly stopped being mutual.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 7, 'question', 'Have you let someone love you fully?', NULL, 'vulnerability', 3, '"Fully" means accepting their love without deflecting, minimizing, or holding part of yourself back.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 8, 'question', 'Do you believe you deserve the love you want?', NULL, 'desire', 3, 'This is about what you believe deep down, even if your actions don''t always reflect it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('embers', 9, 'quote', 'To love and be loved is to feel the sun from both sides.', 'David Viscott', 'love', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 0, 'question', 'Do you know what you''d do if money didn''t matter?', NULL, 'direction', 2, 'Assume your basic needs would still be met — the question is how you''d spend your time.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 1, 'question', 'Are you building someone else''s dream?', NULL, 'purpose', 3, '"Someone else" can be a parent, boss, partner, or a script you inherited without choosing it.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 2, 'quote', 'Your work is to discover your world and then with all your heart give yourself to it.', 'Buddha', 'direction', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 3, 'question', 'Do you feel like you''re on the right path?', NULL, 'direction', 2, '"Right" here means it feels aligned to you, not measured against anyone else''s timeline.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 4, 'vibe', 'Picture where you want to be in five years. Not what — where.', NULL, 'direction', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 5, 'question', 'Have you sacrificed passion for stability?', NULL, 'crossroads', 3, 'This can be one major decision or a pattern of smaller ones over time.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 6, 'question', 'Do you wake up excited about your life?', NULL, 'purpose', 2, 'Think of your general pattern lately, not a single hard morning.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 7, 'question', 'Are you living by someone else''s definition of success?', NULL, 'honesty', 3, '"Someone else''s" can mean family, culture, or a social norm you never actually examined.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 8, 'question', 'Have you followed your curiosity to somewhere unexpected?', NULL, 'curiosity', 2, '"Somewhere" can be a place, a skill, a relationship, or a line of thought — anywhere curiosity led.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('compass', 9, 'quote', 'Not all those who wander are lost.', 'J.R.R. Tolkien', 'direction', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 0, 'question', 'Can you sit in silence without reaching for your phone?', NULL, 'stillness', 2, 'Think of a stretch of a few minutes or more, not a single urge you resist once.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 1, 'vibe', 'Take three slow breaths before continuing.', NULL, 'calm', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 2, 'question', 'Have you found a place where you feel completely calm?', NULL, 'calm', 2, '"Place" can be physical or somewhere you get to mentally, like a memory or state of mind.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 3, 'question', 'Are you comfortable being alone?', NULL, 'solitude', 2, 'This is about extended time alone, not brief solitude, and about comfort rather than preference.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 4, 'quote', 'Almost everything will work again if you unplug it for a few minutes, including you.', 'Anne Lamott', 'rest', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 5, 'question', 'Do you know what peace feels like in your body?', NULL, 'peace', 2, 'This means recognizing physical sensations — like a loosened jaw or slower breath — not just the idea of peace.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 6, 'question', 'Are you always running from silence?', NULL, 'stillness', 3, '"Always" means as a consistent pattern, not that you''ve never once sat quietly.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 7, 'vibe', 'Listen to the quietest sound you can hear right now.', NULL, 'calm', 1, NULL);
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 8, 'question', 'Do you give yourself permission to do nothing?', NULL, 'permission', 2, '"Nothing" means unstructured time with no productive goal, not just a change of activity.');
insert into public.garden_items (garden_id, position, content_type, text, attribution, vibe, difficulty, fine_print) values ('still', 9, 'question', 'Is your inner voice kind or critical?', NULL, 'honesty', 3, 'Think of your general inner tone, not just how you talk to yourself after a single mistake.');
